<?php namespace App\Observers; use App\Models\LegalCase; use App\Services\ActivityLogService; use Illuminate\Support\Facades\Auth; class CaseActivityObserver { protected $activityLogService; public function __construct(ActivityLogService $activityLogService) { $this->activityLogService = $activityLogService; } public function created(LegalCase $legalCase) { $this->logActivity('created', $legalCase, 'تم إنشاء قضية جديدة بنجاح.'); } public function updated(LegalCase $legalCase) { $this->logActivity('updated', $legalCase, 'تم تحديث بيانات القضية.'); } public function deleted(LegalCase $legalCase) { $this->logActivity('deleted', $legalCase, 'تم حذف القضية.'); } protected function logActivity(string $event, LegalCase $legalCase, string $message) { $user = Auth::user(); $this->activityLogService->log([ 'user_id' => $user ? $user->id : null, 'action' => $event, 'model' => LegalCase::class, 'model_id' => $legalCase->id, 'description' => $message, 'changes' => $legalCase->getChanges(), 'ip_address' => request()->ip(), 'user_agent' => request()->userAgent(), ]); } }